        "\u6bcf\u4e00\u4e2a\u821e\u59ff\u90fd\u5145\u6ee1\u4e86\u529b\u91cf\u3002\u6bcf\u4e00\u4e2a\u821e\u59ff\u90fd\u547c\u547c\u4f5c\u54cd\u3002\u6bcf\u4e00\u4e2a\u821e\u59ff\u90fd\u662f\u5149\u548c\u5f71\u7684\u5306\u5306\u53d8\u5e7b\u3002\u6bcf\u4e00\u4e2a\u821e\u59ff\u90fd\u4f7f\u4eba\u6218\u6817\u5728\u6d53\u70c8\u7684\u827a\u672f\u4eab\u53d7\u4e2d\uff0c\u4f7f\u4eba\u53f9\u4e3a\u89c2\u6b62\u3002",
